{
  "domain_analysis": {
    "business_context": "A feature request proposes adding a 'confirmed' status to the Quotes bounded context. The term 'confirmed' is already established in the Orders bounded context with a fundamentally different meaning: paid and immutable. The proposed usage in Quotes means verbally agreed but unpaid — a direct semantic collision.",
    "bounded_context": "Quotes (proposed change) vs Orders (existing definition)",
    "ubiquitous_language": [
      { "term": "Confirmed Order", "definition": "An order that has been paid and is queued for fulfillment. It is immutable — no further changes are permitted." },
      { "term": "Confirmed Quote (PROPOSED — CONFLICTING)", "definition": "A quote where the customer has verbally agreed to terms but payment has NOT yet occurred. It is mutable (payment still pending, customer could withdraw)." },
      { "term": "Quote", "definition": "A priced proposal to a customer, not yet committed to fulfillment." },
      { "term": "Order", "definition": "A committed transaction that progresses through payment, fulfillment, and delivery." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A 'confirmed' order is immutable — once confirmed, no field may be changed.",
      "invariant": true,
      "invariant_justification": "This is a state integrity constraint. If a confirmed order can be mutated, downstream fulfillment, billing, and audit processes are corrupted.",
      "testable_assertion": "Any attempt to modify a confirmed order must be rejected by the system."
    },
    {
      "id": "BR-2",
      "rule": "A 'confirmed' order means payment has been received.",
      "invariant": true,
      "invariant_justification": "Payment receipt is the precondition that distinguishes a confirmed order from a pending one. Without this, fulfillment could begin on unpaid orders.",
      "testable_assertion": "No order may transition to 'confirmed' status without a successful payment record."
    },
    {
      "id": "BR-3",
      "rule": "The proposed 'confirmed' quote is NOT immutable — the customer has only verbally agreed and payment is still pending.",
      "invariant": false,
      "invariant_justification": "This is a soft commitment stage. A customer can withdraw verbal agreement; a sales agent may need to revise terms before payment.",
      "testable_assertion": "A 'confirmed' quote (as proposed) can still be modified or cancelled before payment."
    },
    {
      "id": "BR-4",
      "rule": "The term 'confirmed' must carry a single unambiguous meaning across the domain, or be explicitly scoped to prevent confusion.",
      "invariant": true,
      "invariant_justification": "Ubiquitous language integrity is a foundational DDD invariant. If 'confirmed' means 'paid and immutable' in Orders but 'verbally agreed and mutable' in Quotes, developers, support agents, and business stakeholders WILL conflate them. This leads to bugs where code assumes confirmed = paid when it doesn't, or confirmed = immutable when it isn't.",
      "testable_assertion": "No two bounded contexts may use the same status term with contradictory semantics (paid vs unpaid, immutable vs mutable) without explicit disambiguation."
    }
  ],

  "acceptance_criteria": [],

  "edge_cases": [
    { "scenario": "A developer writes shared logic that checks `status == 'confirmed'` across both quotes and orders, assuming immutability.", "expected_behavior": "The system silently permits mutation of a 'confirmed' quote, corrupting downstream assumptions. This is the primary risk of the naming collision." },
    { "scenario": "A support agent sees 'confirmed' on a quote and tells the customer it's been paid.", "expected_behavior": "Customer confusion and potential trust erosion. The term's existing connotation (paid, locked in) will mislead anyone who works across both contexts." },
    { "scenario": "A reporting dashboard aggregates 'confirmed' items across quotes and orders.", "expected_behavior": "Metrics are polluted — confirmed quotes (unpaid verbal agreements) are counted alongside confirmed orders (paid commitments), giving a false picture of revenue." },
    { "scenario": "Customer verbally agrees, quote moves to 'confirmed', but customer never pays.", "expected_behavior": "The quote must remain cancellable. But if the system treats 'confirmed' as immutable (per Order semantics), the quote becomes stuck." }
  ],

  "business_impact": {
    "financial": "If 'confirmed' quotes are mistakenly treated as revenue-committed (like confirmed orders), financial reporting and forecasting will overstate committed revenue. Verbal agreements are not payment.",
    "operational": "Teams working across Quotes and Orders will be confused by the overloaded term. Support, fulfillment, and engineering will all need to mentally disambiguate which 'confirmed' they're dealing with, increasing error rates.",
    "user": "Sales agents may correctly understand the distinction, but downstream users (support, finance, customers viewing status) will not. A customer told their quote is 'confirmed' may assume they've been charged.",
    "risk": "HIGH. This is a ubiquitous language violation that will cause semantic bugs, reporting errors, and cross-team confusion. The risk compounds over time as more code and processes reference 'confirmed' status.",
    "stakeholders_affected": [
      { "group": "Sales Agents", "impact": "Primary users of the new status. They understand the intent but may confuse it with order confirmation in cross-context workflows." },
      { "group": "Finance/Billing", "impact": "Risk of conflating verbal agreement with payment received. Could distort revenue recognition." },
      { "group": "Customer Support", "impact": "Will see 'confirmed' and may tell customers their order is locked in when it's only a verbal agreement on a quote." },
      { "group": "Engineering", "impact": "Shared enums, status checks, and event handlers that reference 'confirmed' become ambiguous. High bug potential." },
      { "group": "Customers", "impact": "May receive communications saying their quote is 'confirmed' and interpret it as a binding commitment or payment confirmation." }
    ]
  },

  "confidence": {
    "level": 40,
    "reasoning": "The feature request contains a direct contradiction with an established domain definition. 'Confirmed' is already defined as paid+immutable (Orders), and the proposal redefines it as unpaid+mutable (Quotes). These are semantically opposite on two critical dimensions. Cannot write acceptance criteria until the naming contradiction is resolved.",
    "high_confidence_areas": [
      "The semantic collision between 'confirmed order' (paid, immutable) and 'confirmed quote' (unpaid, mutable) is real and dangerous",
      "The business need is legitimate — sales agents need a way to mark verbal customer agreement"
    ],
    "low_confidence_areas": [
      "Whether the organization intends these to be separate bounded contexts with independent language (which could theoretically allow reuse of the term)",
      "Whether there are existing shared enums, APIs, or UIs that would immediately break with overloaded 'confirmed'"
    ],
    "assumptions": [
      "The existing definition of 'confirmed order' is authoritative and in active use",
      "Quotes and Orders share some common infrastructure, UI, or reporting where the term collision would surface"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "The term 'confirmed' is already defined as 'paid and immutable' in the Orders context. The feature request redefines it as 'verbally agreed, unpaid, and mutable' in the Quotes context. These meanings are contradictory on two critical axes: payment status (paid vs unpaid) and mutability (immutable vs mutable). This violates ubiquitous language integrity and will cause bugs, reporting errors, and cross-team confusion.",
      "affected_stakeholders": ["Engineering", "Sales Agents", "Finance/Billing", "Customer Support", "Customers"],
      "options": [
        "A) Rename the quote status to a distinct term that accurately reflects the business state — e.g., 'customer_accepted', 'verbally_agreed', 'terms_accepted', or 'quote_approved'",
        "B) Keep 'confirmed' but enforce strict bounded context separation with explicit context qualifiers everywhere (quote_confirmed vs order_confirmed) — higher complexity, still risks human confusion",
        "C) Redefine 'confirmed' globally to mean 'stakeholder agreement reached' and add a separate 'paid' status to orders — massive breaking change, not recommended"
      ],
      "recommendation": "Option A. Use a term like 'customer_accepted' or 'verbally_agreed' for the quote status. This preserves the established meaning of 'confirmed' in Orders, accurately describes the quote's business state (verbal agreement, no payment), and eliminates the collision entirely. The business need is valid — the naming is the problem, not the feature."
    }
  ],

  "rejection_reasons": [
    { "violation": "Ubiquitous language collision: 'confirmed' already means 'paid and immutable' in Orders. Reusing it to mean 'unpaid and mutable' in Quotes creates a dangerous semantic contradiction.", "business_rule_broken": "BR-4" },
    { "violation": "The proposed 'confirmed quote' is mutable (customer can withdraw, terms can change), contradicting the established invariant that 'confirmed' entities are immutable.", "business_rule_broken": "BR-1" },
    { "violation": "The proposed 'confirmed quote' has no payment, contradicting the established rule that 'confirmed' means payment has been received.", "business_rule_broken": "BR-2" }
  ]
}

